a = input().strip()
b = input().strip()

# Precompute the cost and overlap for each possible starting position in a
cost = [0] * (n - m + 1)
for i in range(n - m + 1):
    current_cost = 0
    for j in range(m):
        if a[i + j] != b[j]:
            current_cost += 1
    cost[i] = current_cost

# Initialize DP table: dp[i][j] = min changes up to position i, with j occurrences
INF = float('inf')
max_k = n - m + 1
dp = [[INF] * (max_k + 2) for _ in range(n + 2)]
dp[0][0] = 0

for i in range(n + 1):
    for k in range(max_k + 1):
        if dp[i][k] == INF:
            continue
        # Option 1: do not take any substring starting at i (if possible)
        if i + 1 <= n:
            if dp[i + 1][k] > dp[i][k]:
                dp[i + 1][k] = dp[i][k]
        # Option 2: take a substring starting at i (if possible)
        if i + m <= n and k + 1 <= max_k:
            new_cost = dp[i][k] + cost[i]
            if dp[i + m][k + 1] > new_cost:
                dp[i + m][k + 1] = new_cost

# Prepare the answer
result = [INF] * (max_k + 1)
for k in range(max_k + 1):
    for i in range(n + 1):
        if dp[i][k] < result[k]:
            result[k] = dp[i][k]

# Handle the output
output = []
for k in range(max_k + 1):
    if result[k] == INF:
        output.append(-1)
    else:
        output.append(result[k])
print(' '.join(map(str, output)))

